import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChatIcon, SendIcon, CHATBOT_QUESTIONS } from '../constants';

interface Message {
  text: string;
  sender: 'user' | 'bot';
  component?: React.ReactNode;
}

const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      text: "Hello! I'm the Vishwa Aadhar assistant. How can I help you? You can select a question below or type your own.",
      sender: 'bot',
    },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [showQuestions, setShowQuestions] = useState(true);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  const toggleChatbot = () => {
    setIsOpen(!isOpen);
  };

  const handleQuestionClick = (question: string, answer: string) => {
    const userMessage: Message = { text: question, sender: 'user' };
    const botMessage: Message = { text: answer, sender: 'bot' };
    setMessages([...messages, userMessage, botMessage]);
  };

  const handleSendMessage = () => {
    if (inputValue.trim() === '') return;

    const userMessage: Message = { text: inputValue, sender: 'user' };
    const botResponse: Message = {
      text: "Thank you for your query. For a detailed response, please get in touch with our expert team.",
      sender: 'bot',
      component: (
        <div className="mt-2">
            <button
                onClick={() => {
                    navigate('/contact');
                    setIsOpen(false);
                }}
                className="bg-green-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-green-700 transition-colors"
            >
                Contact Us
            </button>
        </div>
      )
    };

    setMessages([...messages, userMessage, botResponse]);
    setInputValue('');
  };

  const handleInputKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      handleSendMessage();
    }
  };

  return (
    <>
      <button
        onClick={toggleChatbot}
        className="fixed bottom-6 right-6 z-[999] bg-green-600 text-white p-4 rounded-full shadow-lg hover:bg-green-700 transition-transform transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-offset-2 focus:ring-offset-gray-900"
        aria-label="Toggle chatbot"
      >
        <ChatIcon />
      </button>

      <div
        className={`fixed bottom-24 right-6 z-[998] w-full max-w-sm h-[60vh] max-h-[500px] bg-gray-800 border border-gray-700 rounded-2xl shadow-2xl flex flex-col transition-all duration-300 ease-in-out ${
          isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'
        }`}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4 bg-gray-700 rounded-t-2xl border-b border-gray-600">
          <h3 className="text-lg font-bold text-white">Vishwa Aadhar Assistant</h3>
          <button onClick={toggleChatbot} className="text-gray-400 hover:text-white" aria-label="Close chatbot">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        {/* Messages */}
        <div className="flex-grow p-4 overflow-y-auto">
          {messages.map((msg, index) => (
            <div key={index} className={`flex mb-4 ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div
                className={`max-w-xs lg:max-w-md px-4 py-2 rounded-2xl ${
                  msg.sender === 'user'
                    ? 'bg-green-600 text-white rounded-br-none'
                    : 'bg-gray-700 text-gray-300 rounded-bl-none'
                }`}
              >
                <p className="text-sm">{msg.text}</p>
                {msg.component}
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>

        {/* Questions */}
        {showQuestions && (
            <div className="p-4 border-t border-gray-700">
                <p className="text-xs text-gray-400 mb-2">Or choose a topic:</p>
                <div className="flex flex-wrap gap-2">
                    {CHATBOT_QUESTIONS.map(q => (
                        <button
                            key={q.question}
                            onClick={() => handleQuestionClick(q.question, q.answer)}
                            className="bg-gray-600 text-gray-200 text-sm px-3 py-1 rounded-full hover:bg-gray-500 transition-colors"
                        >
                            {q.question}
                        </button>
                    ))}
                </div>
            </div>
        )}

        {/* Input */}
        <div className="p-4 bg-gray-800 rounded-b-2xl border-t border-gray-700">
          <div className="flex items-center bg-gray-700 rounded-full">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={handleInputKeyPress}
              placeholder="Type your message..."
              className="w-full bg-transparent px-4 py-2 text-white placeholder-gray-400 focus:outline-none"
            />
            <button
              onClick={handleSendMessage}
              className="p-2 text-green-400 hover:text-green-300 transition-colors rounded-full m-1"
              aria-label="Send message"
            >
              <SendIcon />
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

export default Chatbot;

